#include <stdio.h>
int isPossible(int* books, int N, int M, int limit) {
    int count = 1;
    int sum = 0;
    for (int i = 0; i < N; i++) {
        if (books[i] > limit) return 0;
        if (sum + books[i] > limit) {
            count++;
            sum = books[i];
            if (count > M) return 0;
        } else sum += books[i];
    }
    return 1;
}

int allocateBooks(int* books, int N, int M) {
    if (M > N) return -1;

    int low = 0, high = 0;
    for (int i = 0; i < N; i++) {
        if (books[i] > low) low = books[i];
        high += books[i];
    }

    int ans = -1;
    while (low <= high) {
        int mid = low + (high - low) / 2;
        if (isPossible(books, N, M, mid)) {
            ans = mid;
            high = mid - 1;
        } else low = mid + 1;
    }
    return ans;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int books[N];
        for (int i = 0; i < N; i++) scanf("%d", &books[i]);
        printf("%d\n", allocateBooks(books, N, M));
    }
    return 0;
}

